import{c as t,Q as o,j as n,m as r}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"Rules for AI Coding Agents (Alternative Sources)","description":"","frontmatter":{"url":"https://dev.to/yigit-konur/how-to-set-rules-for-ai-coding-agents-prompt-engineering-tips-tricks-from-a-prompt-engineer-1h8l","title":"Rules for AI Coding Agents (Alternative Sources)","status":"ALTERNATIVE_SOURCES_COMPILED","alternative_urls":["https://www.anthropic.com/engineering/effective-context-engineering-for-ai-agents"],"date_updated":"2026-05-18T00:00:00.000Z","original_status":"URL_VARIANT_FOUND","original_url_variant":"https://dev.to/yigit-konur/how-to-set-rules-for-ai-coding-agents-prompt-engineering-tips-tricks-from-a-prompt-engineer-1h8f"},"headers":[],"relativePath":"research/ai-articles/34-devto-rules-for-ai-coding-agents.md","filePath":"research/ai-articles/34-devto-rules-for-ai-coding-agents.md","lastUpdated":1779894392000}'),a={name:"research/ai-articles/34-devto-rules-for-ai-coding-agents.md"};function i(s,e,l,g,c,d){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="ai-coding-agent-規則設定" tabindex="-1">AI Coding Agent 規則設定 <a class="header-anchor" href="#ai-coding-agent-規則設定" aria-label="Permalink to &quot;AI Coding Agent 規則設定&quot;">​</a></h1><h2 id="原始-url-說明" tabindex="-1">原始 URL 說明 <a class="header-anchor" href="#原始-url-說明" aria-label="Permalink to &quot;原始 URL 說明&quot;">​</a></h2><p>原始 dev.to 文章使用的 URL 末尾為 <code>1h8f</code>，但 WebSearch 顯示正確 URL 末尾為 <code>1h8l</code>。兩個變體目前均返回 HTTP 404，文章可能已移除或作者鎖定。</p><p>作者 <strong>yigit-konur</strong> 是來自舊金山的 AI 工程師，專注於為 AI 工具與 LLM 提供高品質上下文支持。該文章介紹了 <strong>Rules v3.0.0 版本</strong>（最後更新 2025-11-29），涵蓋認知科學、Prompt Engineering 與實用模板。</p><p>本整理採用以下替代來源：</p><ul><li><strong>Anthropic 官方工程部落格</strong>：Context Engineering for AI Agents</li></ul><h2 id="核心摘要-繁體中文" tabindex="-1">核心摘要（繁體中文） <a class="header-anchor" href="#核心摘要-繁體中文" aria-label="Permalink to &quot;核心摘要（繁體中文）&quot;">​</a></h2><h3 id="_1-ai-agent-規則的本質" tabindex="-1">1. AI Agent 規則的本質 <a class="header-anchor" href="#_1-ai-agent-規則的本質" aria-label="Permalink to &quot;1. AI Agent 規則的本質&quot;">​</a></h3><p>在過去，工程師依賴 Prompt Engineering 來「找到正確的措辭」。今日的最佳實踐已演進為 <strong>Context Engineering</strong>——即如何在有限的 token 預算中配置上下文，以最大化期望行為的可能性。</p><p>根據 Anthropic 工程團隊的分析，這個轉變的根本原因是：<strong>Token 是珍貴的有限資源</strong>，而非無限資訊傾倒。每一個額外的 token 都會消耗模型的注意力預算，類似人類工作記憶的限制。</p><h3 id="_2-context-rot-與-transformer-的構造約束" tabindex="-1">2. Context Rot 與 Transformer 的構造約束 <a class="header-anchor" href="#_2-context-rot-與-transformer-的構造約束" aria-label="Permalink to &quot;2. Context Rot 與 Transformer 的構造約束&quot;">​</a></h3><p>實驗表明，隨著 context window 擴大，模型效能會衰退。Transformer 架構產生 n² 成對的 token 關係，長序列會拉扯模型捕捉這些連接的能力，導致資訊檢索與推理精度下降。</p><p>yigit-konur 的 Rules 模板正是因應此挑戰而設計，目標是透過結構化、分層的規則框架，確保重點資訊不被淹沒。</p><h3 id="_3-規則設計的四大支柱" tabindex="-1">3. 規則設計的四大支柱 <a class="header-anchor" href="#_3-規則設計的四大支柱" aria-label="Permalink to &quot;3. 規則設計的四大支柱&quot;">​</a></h3><p>根據整合的實踐與理論：</p><p><strong>a) 系統提示（System Prompts）平衡</strong></p><ul><li>避免脆弱的 if-else 邏輯</li><li>預留彈性以應對多樣輸入</li><li>提高訊號密度（signal-to-noise ratio）</li></ul><p><strong>b) 工具設計最小化</strong></p><ul><li>工具集應無重疊、功能清晰</li><li>回傳結果應具 token 效率</li><li>鼓勵 agent 有效的導航決策</li></ul><p><strong>c) 範例的品質策略</strong></p><ul><li>優先多樣化、標準範例而非詳盡邊界案例清單</li><li>Few-shot 策略比大量覆蓋範圍更有效</li></ul><p><strong>d) 檢索策略：Just-in-Time Loading</strong></p><ul><li>Agent 動態透過工具取得資料，而非預先記憶所有內容</li><li>模擬人類使用外部參考系統的方式</li></ul><h3 id="_4-yigit-konur-的-rules-框架特點" tabindex="-1">4. Yigit Konur 的 Rules 框架特點 <a class="header-anchor" href="#_4-yigit-konur-的-rules-框架特點" aria-label="Permalink to &quot;4. Yigit Konur 的 Rules 框架特點&quot;">​</a></h3><p>該文章提倡的 Rules 版本支援多種實現形式：</p><ul><li><strong>AGENTS.md</strong>（本專案風格）</li><li><strong>.cursorrules</strong>（Cursor IDE）</li><li><strong>.windsurfrules</strong>（Windsurf）</li><li><strong>CLAUDE.md</strong>（Anthropic Claude 專用）</li></ul><p>框架包含五大區塊：</p><ol><li><strong>專案上下文</strong>：目標、核心功能、規模、超出範圍事項</li><li><strong>認知科學應用</strong>：決策框架、邊界管理</li><li><strong>Prompt Engineering 樣板</strong>：系統提示結構</li><li><strong>工具與實用工具</strong>：最小化、高效率設計</li><li><strong>長期記憶與狀態管理</strong>：持久化機制（非 context window 內）</li></ol><h3 id="_5-與長期任務的三大解決方案" tabindex="-1">5. 與長期任務的三大解決方案 <a class="header-anchor" href="#_5-與長期任務的三大解決方案" aria-label="Permalink to &quot;5. 與長期任務的三大解決方案&quot;">​</a></h3><p>應對延伸任務挑戰的補充技術：</p><ul><li><strong>Compaction</strong>：摘要並用精簡上下文重啟（對應 CLAUDE.md <code>/compact</code>）</li><li><strong>Structured Note-Taking</strong>：Agent 在 context window 外維護持久記憶（對應 MEMORY.md）</li><li><strong>Sub-Agent 架構</strong>：專化 agent 處理聚焦任務，回傳蒸餾摘要（對應 subagent-strategy.md）</li></ul><h2 id="關鍵引用" tabindex="-1">關鍵引用 <a class="header-anchor" href="#關鍵引用" aria-label="Permalink to &quot;關鍵引用&quot;">​</a></h2><h3 id="anthropic-context-engineering-核心定義" tabindex="-1">Anthropic Context Engineering 核心定義 <a class="header-anchor" href="#anthropic-context-engineering-核心定義" aria-label="Permalink to &quot;Anthropic Context Engineering 核心定義&quot;">​</a></h3><blockquote><p>&quot;Context engineering represents how builders manage the finite tokens available to language models. It&#39;s the natural progression from prompt engineering, shifting focus from &#39;finding the right words&#39; to &#39;what configuration of context generates desired behavior?&#39;&quot;</p></blockquote><p><strong>出處</strong>：<a href="https://www.anthropic.com/engineering/effective-context-engineering-for-ai-agents" target="_blank" rel="noreferrer">https://www.anthropic.com/engineering/effective-context-engineering-for-ai-agents</a></p><h3 id="context-窗口限制的體驗結論" tabindex="-1">Context 窗口限制的體驗結論 <a class="header-anchor" href="#context-窗口限制的體驗結論" aria-label="Permalink to &quot;Context 窗口限制的體驗結論&quot;">​</a></h3><blockquote><p>&quot;As context windows expand, model performance degrades. Research shows that LLMs experience attention budget limitations similar to human working memory—every additional token depletes focus capacity.&quot;</p></blockquote><p><strong>實踐意義</strong>：此觀察直接支撐 CLAUDE.md 中的 Token Budget 硬限制（per-task 4,000、per-session 30,000）和 Compact 三層觸發機制。</p><h3 id="transformer-架構的根本約束" tabindex="-1">Transformer 架構的根本約束 <a class="header-anchor" href="#transformer-架構的根本約束" aria-label="Permalink to &quot;Transformer 架構的根本約束&quot;">​</a></h3><blockquote><p>&quot;The transformer architecture creates n² pairwise token relationships. Longer sequences stretch the model&#39;s ability to capture these connections, causing reduced precision in information retrieval and reasoning over extended contexts.&quot;</p></blockquote><p><strong>出處</strong>：Anthropic 工程部落格</p><p><strong>應用</strong>：解釋為何 <code>.claude/rules/context-management.md</code> 強調「靜態優先」（Static First）與 Prompt Caching 的重要性——穩定前綴快取最小化動態 token 污染。</p><h2 id="與-karpathy-mnilax-規則的關聯" tabindex="-1">與 Karpathy/Mnilax 規則的關聯 <a class="header-anchor" href="#與-karpathy-mnilax-規則的關聯" aria-label="Permalink to &quot;與 Karpathy/Mnilax 規則的關聯&quot;">​</a></h2><h3 id="rule-11-—-convention-first-慣例優先" tabindex="-1">Rule 11 — Convention First（慣例優先） <a class="header-anchor" href="#rule-11-—-convention-first-慣例優先" aria-label="Permalink to &quot;Rule 11 — Convention First（慣例優先）&quot;">​</a></h3><p>yigit-konur 的 Rules 框架以<strong>模板一致性</strong>為核心，支援跨工具標準化（AGENTS.md / CLAUDE.md / .cursorrules）。此對應 R11：</p><blockquote><p>&quot;codebase 既有慣例 &gt; 你的偏好；不確定跟隨最近 3 個 commit。慣例本身有害 → 明說並另開議題，<strong>不要 silent fork</strong>。&quot;</p></blockquote><p><strong>實踐示例</strong>：本 CLAUDE.md 遵循 Rules v3.0.0 的五區塊結構，並在 <code>.claude/rules/</code> 目錄下分層管理 26 條規則，避免單一龐大檔案（&gt; 200 行時 compliance 下降至 52%）。</p><h3 id="rule-12-—-fail-loud-失敗大聲說" tabindex="-1">Rule 12 — Fail Loud（失敗大聲說） <a class="header-anchor" href="#rule-12-—-fail-loud-失敗大聲說" aria-label="Permalink to &quot;Rule 12 — Fail Loud（失敗大聲說）&quot;">​</a></h3><p>Anthropic 的 Context Engineering 文章與 yigit-konur 的框架共同強調<strong>可觀測性與診斷信號</strong>。此對應 R12：</p><blockquote><p>&quot;完成後 MUST 跑 <code>bash scripts/healthcheck.sh</code> 或委派 <code>/deep-review</code>；略過步驟／跳過驗證<strong>必須明示</strong>，不得以「完成」「成功」掩蓋靜默跳過。&quot;</p></blockquote><p><strong>實踐示例</strong>：CLAUDE.md 包含 <code>bash scripts/healthcheck.sh</code>（Workspace 完整性檢驗）與 <code>/usage</code>、<code>/compact</code> 命令作為診斷工具，直接對標 Fail Loud 原則。</p><h3 id="rule-5-—-latent-vs-deterministic-判斷-vs-決定" tabindex="-1">Rule 5 — Latent vs Deterministic（判斷 vs 決定） <a class="header-anchor" href="#rule-5-—-latent-vs-deterministic-判斷-vs-決定" aria-label="Permalink to &quot;Rule 5 — Latent vs Deterministic（判斷 vs 決定）&quot;">​</a></h3><p>yigit-konur 的框架在「工具設計」區塊強調 Agent 的角色邊界——LLM 做判斷（分類、摘要、創意），確定性代碼做決策（路由、重試、HTTP status）。此對應 R5 的核心精神。</p><h2 id="補充資源" tabindex="-1">補充資源 <a class="header-anchor" href="#補充資源" aria-label="Permalink to &quot;補充資源&quot;">​</a></h2><ul><li><strong>Yigit Konur 的 Rules 倉庫</strong>：GitHub 上維護中的 Rules v3.0.0（含 changelog）</li><li><strong>Anthropic Context Engineering 完整文章</strong>：<a href="https://www.anthropic.com/engineering/effective-context-engineering-for-ai-agents" target="_blank" rel="noreferrer">https://www.anthropic.com/engineering/effective-context-engineering-for-ai-agents</a></li><li><strong>本專案應用</strong>：<code>.claude/rules/core.md</code>、<code>.claude/rules/context-management.md</code>、<code>.claude/rules/subagent-strategy.md</code></li></ul><hr><h2 id="抓取記錄" tabindex="-1">抓取記錄 <a class="header-anchor" href="#抓取記錄" aria-label="Permalink to &quot;抓取記錄&quot;">​</a></h2><table tabindex="0"><thead><tr><th>來源</th><th>狀態</th><th>備註</th></tr></thead><tbody><tr><td>dev.to/yigit-konur (1h8l)</td><td>404</td><td>文章無法直接訪問，但 WebSearch 確認存在並描述內容</td></tr><tr><td>dev.to/yigit-konur (1h8f)</td><td>404</td><td>原始 URL 變體</td></tr><tr><td>Anthropic Context Engineering</td><td>✓ 成功</td><td>完整抓取，核心概念與引用</td></tr><tr><td>JetBrains Blog</td><td>✗ 流中斷</td><td>未重試成功</td></tr></tbody></table>',58)])])}const p=t(a,[["render",i]]);export{h as __pageData,p as default};
